INSERT INTO "umkm" VALUES(46,'Deka Cathering','Deka Katering merupakan usaha kuliner yang menyediakan berbagai pilihan makanan dan kue untuk kebutuhan sehari-hari maupun acara. Produk yang ditawarkan meliputi aneka masakan katering, kue basah seperti bikang, pastel, dan roti dengan harga mulai dari Rp3.000 per buah, serta kue kering seperti semprit, nastar, dan berbagai jenis keripik. Dengan jam operasional yang fleksibel, Deka Katering berkomitmen menghadirkan produk yang lezat, berkualitas, dan sesuai kebutuhan pelanggan.','Makanan','Ibu Mustini','Gg Merdeka Timur. RT.10/RW.02, Krajan, Ngadirejo, Kec Kromengan, Kabupaten Malang','-8.1305745','112.5200073','','6285736988611','24 jam');
